# Generated by anthropic (claude-opus-4-6)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(
            name: 'IMAGE_NAME',
            defaultValue: 'my-application',
            description: 'Name of the Docker image to build'
        )
        string(
            name: 'IMAGE_TAG',
            defaultValue: 'latest',
            description: 'Tag for the Docker image (e.g., latest, v1.0.0, dev-build)'
        )
        string(
            name: 'REGISTRY_URL',
            defaultValue: 'https://registry.hub.docker.com',
            description: 'Docker registry URL to push the image to (e.g., https://registry.hub.docker.com, https://your-ecr-url.amazonaws.com, https://gcr.io)'
        )
        string(
            name: 'REGISTRY_CREDENTIALS_ID',
            defaultValue: 'docker-registry-credentials',
            description: 'Jenkins credentials ID for the Docker registry authentication'
        )
        string(
            name: 'DOCKERFILE_PATH',
            defaultValue: '.',
            description: 'Path to the Dockerfile context directory'
        )
        string(
            name: 'DOCKERFILE_NAME',
            defaultValue: 'Dockerfile',
            description: 'Name of the Dockerfile to use'
        )
        booleanParam(
            name: 'PUSH_IMAGE',
            defaultValue: true,
            description: 'Whether to push the image to the registry after building'
        )
        booleanParam(
            name: 'USE_CACHE',
            defaultValue: true,
            description: 'Whether to use Docker build cache'
        )
    }

    environment {
        FULL_IMAGE_NAME = "${params.IMAGE_NAME}:${params.IMAGE_TAG}"
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    if (!params.IMAGE_NAME?.trim()) {
                        error('IMAGE_NAME parameter cannot be empty')
                    }
                    if (!params.IMAGE_TAG?.trim()) {
                        error('IMAGE_TAG parameter cannot be empty')
                    }
                    if (!params.REGISTRY_URL?.trim()) {
                        error('REGISTRY_URL parameter cannot be empty')
                    }
                    if (!params.REGISTRY_CREDENTIALS_ID?.trim()) {
                        error('REGISTRY_CREDENTIALS_ID parameter cannot be empty')
                    }

                    echo "========================================="
                    echo "Build Configuration:"
                    echo "  Image Name:    ${params.IMAGE_NAME}"
                    echo "  Image Tag:     ${params.IMAGE_TAG}"
                    echo "  Full Image:    ${env.FULL_IMAGE_NAME}"
                    echo "  Registry URL:  ${params.REGISTRY_URL}"
                    echo "  Dockerfile:    ${params.DOCKERFILE_PATH}/${params.DOCKERFILE_NAME}"
                    echo "  Push Image:    ${params.PUSH_IMAGE}"
                    echo "  Use Cache:     ${params.USE_CACHE}"
                    echo "========================================="
                }
            }
        }

        stage('Checkout') {
            steps {
                checkout scm
            }
        }

        stage('Build Docker Image') {
            steps {
                script {
                    def buildArgs = "-f ${params.DOCKERFILE_PATH}/${params.DOCKERFILE_NAME}"

                    if (!params.USE_CACHE) {
                        buildArgs += ' --no-cache'
                    }

                    buildArgs += " ${params.DOCKERFILE_PATH}"

                    echo "Building Docker image: ${env.FULL_IMAGE_NAME}"
                    echo "Build arguments: ${buildArgs}"

                    dockerImage = docker.build("${env.FULL_IMAGE_NAME}", buildArgs)

                    echo "Docker image built successfully: ${env.FULL_IMAGE_NAME}"
                }
            }
        }

        stage('Verify Image') {
            steps {
                script {
                    echo "Verifying built Docker image..."

                    sh "docker inspect ${env.FULL_IMAGE_NAME}"

                    sh "docker history ${env.FULL_IMAGE_NAME}"

                    def imageSize = sh(
                        script: "docker image ls ${params.IMAGE_NAME}:${params.IMAGE_TAG} --format '{{.Size}}'",
                        returnStdout: true
                    ).trim()

                    echo "Image size: ${imageSize}"
                }
            }
        }

        stage('Push Docker Image') {
            when {
                expression { return params.PUSH_IMAGE }
            }
            steps {
                script {
                    echo "Pushing image to registry: ${params.REGISTRY_URL}"

                    docker.withRegistry(params.REGISTRY_URL, params.REGISTRY_CREDENTIALS_ID) {
                        dockerImage.push(params.IMAGE_TAG)

                        if (params.IMAGE_TAG != 'latest') {
                            echo "Also tagging and pushing as 'latest'"
                            dockerImage.push('latest')
                        }
                    }

                    echo "Docker image pushed successfully to ${params.REGISTRY_URL}/${env.FULL_IMAGE_NAME}"
                }
            }
        }
    }

    post {
        success {
            echo "========================================="
            echo "Pipeline completed successfully!"
            echo "Image: ${env.FULL_IMAGE_NAME}"
            if (params.PUSH_IMAGE) {
                echo "Pushed to: ${params.REGISTRY_URL}"
            } else {
                echo "Image was built locally only (push was skipped)"
            }
            echo "========================================="
        }
        failure {
            echo "========================================="
            echo "Pipeline FAILED!"
            echo "Image: ${env.FULL_IMAGE_NAME}"
            echo "Registry: ${params.REGISTRY_URL}"
            echo "========================================="
        }
        always {
            script {
                echo "Cleaning up local Docker images..."
                sh "docker rmi ${env.FULL_IMAGE_NAME} || true"

                if (params.IMAGE_TAG != 'latest') {
                    sh "docker rmi ${params.IMAGE_NAME}:latest || true"
                }
            }
            cleanWs()
        }
    }
}